import{_ as i,o as t,c as e,a2 as l}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"交互设计 Roadmap：从零基础到复杂体验设计","description":"","frontmatter":{},"headers":[],"relativePath":"03-interaction-design/roadmap.md","filePath":"03-interaction-design/roadmap.md","lastUpdated":1784212366000}'),r={name:"03-interaction-design/roadmap.md"};function o(n,a,s,h,d,c){return t(),e("div",null,[...a[0]||(a[0]=[l('<h1 id="交互设计-roadmap-从零基础到复杂体验设计" tabindex="-1">交互设计 Roadmap：从零基础到复杂体验设计 <a class="header-anchor" href="#交互设计-roadmap-从零基础到复杂体验设计" aria-label="Permalink to &quot;交互设计 Roadmap：从零基础到复杂体验设计&quot;">​</a></h1><p>这是一条可以独立执行的交互设计路线。学习不以用户访谈为前提，而是让“原则学习、产品拆解、重新设计、实现验证”同步进行。交互不是把页面画漂亮，而是帮助用户理解、行动、获得反馈并从错误中恢复。</p><h2 id="能力阶梯" tabindex="-1">能力阶梯 <a class="header-anchor" href="#能力阶梯" aria-label="Permalink to &quot;能力阶梯&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阶段</th><th>能力目标</th><th>代表产出</th></tr></thead><tbody><tr><td>入门</td><td>看懂界面元素、状态与基础原则</td><td>界面与状态分析</td></tr><tr><td>初级</td><td>能还原任务流程并发现交互问题</td><td>功能拆解、流程图、状态清单</td></tr><tr><td>中级</td><td>能设计完整流程与可用原型</td><td>中保真原型和验证报告</td></tr><tr><td>高级</td><td>能处理 B 端、协作与 AI 复杂交互</td><td>权限、审批或 Agent 工作区原型</td></tr><tr><td>专项</td><td>能沉淀模式并与工程共同落地</td><td>交互模式库和 Design System 规范</td></tr></tbody></table><hr><h2 id="阶段零-交互设计基础" tabindex="-1">阶段零：交互设计基础 <a class="header-anchor" href="#阶段零-交互设计基础" aria-label="Permalink to &quot;阶段零：交互设计基础&quot;">​</a></h2><h3 id="基本语言" tabindex="-1">基本语言 <a class="header-anchor" href="#基本语言" aria-label="Permalink to &quot;基本语言&quot;">​</a></h3><ul><li>[ ] 用户目标、任务、场景、入口、路径和完成标准。</li><li>[ ] 页面、弹窗、抽屉、浮层、导航、表单、列表和详情。</li><li>[ ] 信息架构、用户流程、任务流程、状态和反馈。</li><li>[ ] 线框图、低/中/高保真原型与设计规范的用途。</li><li>[ ] 区分产品问题、交互问题、视觉问题和工程问题。</li></ul><h3 id="基础原则" tabindex="-1">基础原则 <a class="header-anchor" href="#基础原则" aria-label="Permalink to &quot;基础原则&quot;">​</a></h3><ul><li>[ ] 心智模型、概念模型和现实世界映射。</li><li>[ ] 可见性、可供性、反馈、一致性和约束。</li><li>[ ] 识别优于回忆、认知负荷和信息分组。</li><li>[ ] 用户控制、撤销、容错、错误预防和恢复。</li><li>[ ] 渐进披露、默认值、熟悉性与学习成本。</li><li>[ ] Fitts、Hick 等规律的适用边界，不机械套公式。</li></ul><p>必做：为十个页面标注用户目标、第一视觉焦点、主要操作、系统反馈、错误恢复和可以删除的信息。</p><p>验收：能使用一致的设计语言解释界面为什么有效或为什么令人困惑，而不只说“好看”或“不好用”。</p><hr><h2 id="阶段一-思考、产品拆解与重新设计" tabindex="-1">阶段一：思考、产品拆解与重新设计 <a class="header-anchor" href="#阶段一-思考、产品拆解与重新设计" aria-label="Permalink to &quot;阶段一：思考、产品拆解与重新设计&quot;">​</a></h2><p>每次只拆一个真实任务，把观察、推理和实践放在同一份记录中。</p><ul><li>[ ] 记录产品、版本、平台、日期和本次任务。</li><li>[ ] 还原入口、前置条件、主流程、分支、异常与完成状态。</li><li>[ ] 列出初始、空、加载、成功、失败、无权限、离线和冲突状态。</li><li>[ ] 分析信息层级、操作层级、默认值、文案和渐进披露。</li><li>[ ] 识别产品使用的交互模式及其适用条件。</li><li>[ ] 用启发式原则解释优点和问题，区分事实与推断。</li><li>[ ] 与至少一个同类产品或现实工作流比较。</li><li>[ ] 画出重新设计的流程或线框图。</li><li>[ ] 写出改动的收益、代价、风险和工程实现注意事项。</li><li>[ ] 条件允许时实现关键交互，验证键盘、响应式和状态切换。</li></ul><p>验收：连续完成 30 个任务级拆解，其中至少 10 个包含重新设计，至少 3 个实现为可交互原型或前端页面。</p><hr><h2 id="阶段二-个人可执行的研究与验证" tabindex="-1">阶段二：个人可执行的研究与验证 <a class="header-anchor" href="#阶段二-个人可执行的研究与验证" aria-label="Permalink to &quot;阶段二：个人可执行的研究与验证&quot;">​</a></h2><h3 id="无需访谈的证据来源" tabindex="-1">无需访谈的证据来源 <a class="header-anchor" href="#无需访谈的证据来源" aria-label="Permalink to &quot;无需访谈的证据来源&quot;">​</a></h3><ul><li>[ ] 产品评论、公开 Issue、帮助文档、更新日志和社区问题。</li><li>[ ] 竞品任务对比、历史版本对比和跨平台对比。</li><li>[ ] Cognitive Walkthrough：模拟新用户逐步判断是否知道目标、操作和反馈。</li><li>[ ] Heuristic Evaluation：按一致性、反馈、控制、容错等原则系统检查。</li><li>[ ] Accessibility Audit：键盘、焦点、语义、对比度、缩放和读屏基础检查。</li><li>[ ] 状态审计：检查正常路径之外的空、错、慢、断、冲突和权限场景。</li><li>[ ] Dogfooding 与任务日志：真实使用并记录耗时、误操作、绕路和恢复。</li><li>[ ] 已有埋点、热图、搜索词、错误日志和客服材料；使用时注意权限与隐私。</li></ul><h3 id="原型验证" tabindex="-1">原型验证 <a class="header-anchor" href="#原型验证" aria-label="Permalink to &quot;原型验证&quot;">​</a></h3><ul><li>[ ] 为原型定义真实任务、成功条件和观察项。</li><li>[ ] 自测时使用认知走查，不把熟悉设计当作用户一定能理解。</li><li>[ ] 使用键盘、窄屏、慢网、空数据和错误响应主动制造边界。</li><li>[ ] 比较改版前后步骤数、完成率、时间、错误与认知成本。</li><li>[ ] 如果能邀请体验者，可做可用性测试；它是增强证据，不是个人学习的准入条件。</li><li>[ ] 根据证据修改设计，并记录哪些问题仍是假设。</li></ul><p>验收：完成一份包含原则检查、认知走查、状态审计、无障碍检查和改版对比的验证报告。</p><hr><h2 id="阶段三-信息架构" tabindex="-1">阶段三：信息架构 <a class="header-anchor" href="#阶段三-信息架构" aria-label="Permalink to &quot;阶段三：信息架构&quot;">​</a></h2><p>学习分类、导航、页面层级、搜索、标签、卡片分类、站点地图和渐进披露。</p><p>Todo：</p><ul><li>[ ] 绘制一个复杂产品的现有站点地图。</li><li>[ ] 标记重复、混乱和层级过深的入口。</li><li>[ ] 按任务、角色或业务对象重新分类。</li><li>[ ] 设计顶部、侧边、Tab、面包屑和搜索的边界。</li><li>[ ] 通过树状结构走查、查找任务或已有行为数据验证目标功能是否容易找到。</li></ul><p>验收：能对几十个功能建立清晰分类，并解释为什么使用页面、弹窗、抽屉或行内编辑。</p><hr><h2 id="阶段四-用户流程与状态" tabindex="-1">阶段四：用户流程与状态 <a class="header-anchor" href="#阶段四-用户流程与状态" aria-label="Permalink to &quot;阶段四：用户流程与状态&quot;">​</a></h2><p>学习 User Flow、Task Flow、Journey Map、主流程、分支、异常、中断和恢复。</p><p>所有功能至少检查：</p><ul><li>[ ] 初始。</li><li>[ ] 空。</li><li>[ ] 加载。</li><li>[ ] 成功。</li><li>[ ] 失败。</li><li>[ ] 部分成功。</li><li>[ ] 无权限。</li><li>[ ] 离线。</li><li>[ ] 数据过期。</li><li>[ ] 取消。</li><li>[ ] 重试。</li><li>[ ] 并发冲突。</li></ul><p>验收：交付不再只有正常页面，而是流程、状态、异常、恢复、反馈和下一步。</p><hr><h2 id="阶段五-交互模式库" tabindex="-1">阶段五：交互模式库 <a class="header-anchor" href="#阶段五-交互模式库" aria-label="Permalink to &quot;阶段五：交互模式库&quot;">​</a></h2><h3 id="导航" tabindex="-1">导航 <a class="header-anchor" href="#导航" aria-label="Permalink to &quot;导航&quot;">​</a></h3><p>Sidebar、Top Navigation、Tabs、Breadcrumb、Command Palette、Stepper。</p><h3 id="输入" tabindex="-1">输入 <a class="header-anchor" href="#输入" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p>Form、Inline Edit、Auto Complete、Tag Input、Date Picker、Upload、Rich Text Editor。</p><h3 id="数据" tabindex="-1">数据 <a class="header-anchor" href="#数据" aria-label="Permalink to &quot;数据&quot;">​</a></h3><p>Table、List、Card、Tree、Timeline、Dashboard、Chart。</p><h3 id="反馈" tabindex="-1">反馈 <a class="header-anchor" href="#反馈" aria-label="Permalink to &quot;反馈&quot;">​</a></h3><p>Toast、Alert、Inline Error、Progress、Skeleton、Empty State、Result Page。</p><h3 id="操作" tabindex="-1">操作 <a class="header-anchor" href="#操作" aria-label="Permalink to &quot;操作&quot;">​</a></h3><p>Create、Edit、Delete、Batch、Drag、Undo、Retry、Save Draft。</p><h3 id="协作" tabindex="-1">协作 <a class="header-anchor" href="#协作" aria-label="Permalink to &quot;协作&quot;">​</a></h3><p>Comment、Mention、Share、Notification、Presence、Version History、Conflict Resolution。</p><p>每个模式记录：用户目标、适用/不适用场景、流程、状态、原则、错误案例、优秀产品、工程实现、可访问性和指标。</p><p>验收：面对需求能说明它属于哪种模式、有哪些方案、为什么选当前方案、主要风险是什么。</p><hr><h2 id="阶段六-复杂-b-端交互" tabindex="-1">阶段六：复杂 B 端交互 <a class="header-anchor" href="#阶段六-复杂-b-端交互" aria-label="Permalink to &quot;阶段六：复杂 B 端交互&quot;">​</a></h2><h3 id="表格" tabindex="-1">表格 <a class="header-anchor" href="#表格" aria-label="Permalink to &quot;表格&quot;">​</a></h3><ul><li>[x] <a href="./notes/06-interaction-patterns/02-data/table">信息层级、默认列和列配置</a>。</li><li>[x] <a href="./notes/06-interaction-patterns/02-data/table">固定列、横向滚动、排序、筛选和分页</a>。</li><li>[x] <a href="./notes/06-interaction-patterns/02-data/table">批量操作、跨页选择和不可选行</a>。</li><li>[x] <a href="./notes/06-interaction-patterns/02-data/table">行内编辑、树形数据和保存视图</a>。</li><li>[x] <a href="./notes/06-interaction-patterns/02-data/table">导出、权限字段和大数据性能</a>。</li></ul><h3 id="表单" tabindex="-1">表单 <a class="header-anchor" href="#表单" aria-label="Permalink to &quot;表单&quot;">​</a></h3><ul><li>[x] <a href="./notes/06-interaction-patterns/01-input/form">字段分组、默认值、必填与选填</a>。</li><li>[x] <a href="./notes/06-interaction-patterns/01-input/form">校验时机、异步校验和字段依赖</a>。</li><li>[x] <a href="./notes/06-interaction-patterns/01-input/form">草稿、自动保存、离开提醒</a>。</li><li>[x] <a href="./notes/06-interaction-patterns/01-input/form">提交失败保留输入</a>。</li><li>[x] <a href="./notes/06-interaction-patterns/01-input/form">服务端错误和多人冲突</a>。</li></ul><h3 id="权限" tabindex="-1">权限 <a class="header-anchor" href="#权限" aria-label="Permalink to &quot;权限&quot;">​</a></h3><ul><li>[x] <a href="./notes/07-enterprise-interactions/01-permission-states-data-scope">无权限、只读、字段权限、数据范围</a>。</li><li>[x] <a href="./notes/07-enterprise-interactions/02-temporary-access-request-expiry">临时权限、申请权限和权限过期</a>。</li><li>[x] <a href="./notes/07-enterprise-interactions/01-permission-states-data-scope">说明限制原因和权限获取方式</a>。</li></ul><h3 id="审批" tabindex="-1">审批 <a class="header-anchor" href="#审批" aria-label="Permalink to &quot;审批&quot;">​</a></h3><ul><li>[x] <a href="./notes/07-enterprise-interactions/03-approval-workflow-state-exceptions">当前节点、下一节点、审批人和预计时间</a>。</li><li>[x] <a href="./notes/07-enterprise-interactions/03-approval-workflow-state-exceptions">驳回、撤回、转交、加签、抄送</a>。</li><li>[x] <a href="./notes/07-enterprise-interactions/03-approval-workflow-state-exceptions">历史、超时、异常中断和并行审批</a>。</li></ul><hr><h2 id="阶段七-视觉基础、动效与无障碍" tabindex="-1">阶段七：视觉基础、动效与无障碍 <a class="header-anchor" href="#阶段七-视觉基础、动效与无障碍" aria-label="Permalink to &quot;阶段七：视觉基础、动效与无障碍&quot;">​</a></h2><p>学习视觉层级、对齐、亲密性、重复、对比、留白、字体、色彩角色、图标和动效目的。</p><p>Todo：</p><ul><li>[x] <a href="./notes/08-visual-motion-accessibility/01-visual-hierarchy-spacing-typography-color-icons">页面建立一个与当前任务匹配的主要视觉焦点</a>。</li><li>[x] <a href="./notes/08-visual-motion-accessibility/01-visual-hierarchy-spacing-typography-color-icons">使用系统化间距和有限字体层级</a>。</li><li>[x] <a href="./notes/08-visual-motion-accessibility/01-visual-hierarchy-spacing-typography-color-icons">颜色不是唯一信息表达方式</a>。</li><li>[x] <a href="./notes/08-visual-motion-accessibility/02-motion-state-transitions-reduced-motion">动效说明元素从哪来、去哪和状态如何变化</a>。</li><li>[x] <a href="./notes/08-visual-motion-accessibility/02-motion-state-transitions-reduced-motion">高频操作避免冗长动画</a>。</li><li>[x] <a href="./notes/08-visual-motion-accessibility/03-keyboard-focus-accessible-interaction">支持键盘、焦点和减少动画设置</a>。</li></ul><p>验收：能独立完成结构清晰、层级合理、可访问的中保真方案。</p><hr><h2 id="阶段八-ai-产品交互" tabindex="-1">阶段八：AI 产品交互 <a class="header-anchor" href="#阶段八-ai-产品交互" aria-label="Permalink to &quot;阶段八：AI 产品交互&quot;">​</a></h2><h3 id="chat-与-streaming" tabindex="-1">Chat 与 Streaming <a class="header-anchor" href="#chat-与-streaming" aria-label="Permalink to &quot;Chat 与 Streaming&quot;">​</a></h3><ul><li>[x] <a href="./notes/09-ai-product-interaction/01-chat-streaming">澄清需求、多轮、停止、重试、继续</a>。</li><li>[x] <a href="./notes/09-ai-product-interaction/01-chat-streaming">首 Token、部分结果、断线、中断和恢复</a>。</li></ul><h3 id="artifact" tabindex="-1">Artifact <a class="header-anchor" href="#artifact" aria-label="Permalink to &quot;Artifact&quot;">​</a></h3><ul><li>[x] <a href="./notes/09-ai-product-interaction/02-artifact-editing-versioning">创建、局部修改、版本、Diff、恢复、导出</a>。</li><li>[x] <a href="./notes/09-ai-product-interaction/02-artifact-editing-versioning">区分用户修改和 AI 修改</a>。</li></ul><h3 id="tool-call-与-approval" tabindex="-1">Tool Call 与 Approval <a class="header-anchor" href="#tool-call-与-approval" aria-label="Permalink to &quot;Tool Call 与 Approval&quot;">​</a></h3><ul><li>[x] <a href="./notes/09-ai-product-interaction/03-tool-call-approval">展示工具、参数、影响、风险和结果</a>。</li><li>[x] <a href="./notes/09-ai-product-interaction/03-tool-call-approval">高风险写操作必须确认</a>。</li></ul><h3 id="agent-task" tabindex="-1">Agent Task <a class="header-anchor" href="#agent-task" aria-label="Permalink to &quot;Agent Task&quot;">​</a></h3><ul><li>[x] <a href="./notes/09-ai-product-interaction/04-agent-task-control">目标、计划、步骤、当前进度</a>。</li><li>[x] <a href="./notes/09-ai-product-interaction/04-agent-task-control">暂停、取消、恢复、失败步骤和人工接管</a>。</li></ul><h3 id="citation-与-memory" tabindex="-1">Citation 与 Memory <a class="header-anchor" href="#citation-与-memory" aria-label="Permalink to &quot;Citation 与 Memory&quot;">​</a></h3><ul><li>[x] <a href="./notes/09-ai-product-interaction/05-citation-memory">引用定位原文、来源日期和推断说明</a>。</li><li>[x] <a href="./notes/09-ai-product-interaction/05-citation-memory">记忆可查看、修改、删除、关闭并说明作用范围</a>。</li></ul><p>验收：用户始终知道 AI 正在做什么，可以停止、修改、确认、恢复，并能判断结果可信度。</p><hr><h2 id="学习资源" tabindex="-1">学习资源 <a class="header-anchor" href="#学习资源" aria-label="Permalink to &quot;学习资源&quot;">​</a></h2><p>书籍：设计心理学、点石成金、About Face、用户体验要素、Designing Interfaces、简约至上、微交互、Refactoring UI。</p><p>网站：Nielsen Norman Group、Laws of UX、Baymard Institute、Mobbin、Page Flows、UI Sources、Material Design、Apple HIG、Carbon Design System。</p><hr>',86)])])}const m=i(r,[["render",o]]);export{u as __pageData,m as default};
